// ErrAccountNotFound is returned by ResolveActiveEmail when Config.ActiveEmail
// names an account that isn't present in the token store. Callers (notably the
// HTTP client) surface this with the list of known accounts so the user can
// pick one or run `auth login --chrome` to populate it.
var ErrAccountNotFound = errors.New("account not found in token store")

type Config struct {
	BaseURL       string            `toml:"base_url"`
	AuthHeaderVal string            `toml:"auth_header"`
	Headers       map[string]string `toml:"headers,omitempty"`
	AuthSource    string            `toml:"-"`
	AccessToken   string            `toml:"access_token"`
	RefreshToken  string            `toml:"refresh_token"`
	TokenExpiry   time.Time         `toml:"token_expiry"`
	ClientID      string            `toml:"client_id"`
	ClientSecret  string            `toml:"client_secret"`
	Path          string            `toml:"-"`
	SuperhumanJwt string            `toml:"jwt"`

	// ActiveEmail selects which account in the token store the CLI should
	// use. When empty, ResolveActiveEmail picks the most-recently-used
	// account. Set via config.toml `active_email = "..."` or (in U6) via
	// the `--account <email>` global flag.
	ActiveEmail string `toml:"active_email"`

	// RefreshFunc is a test seam for the token-refresh path. Production
	// callers leave it nil and the client falls through to auth.Refresh.
	// Tests inject a stub that points at a mocked Firebase endpoint or
	// returns a canned token without doing network I/O. Not serialized.
	RefreshFunc func(ctx context.Context, email string, store *auth.Store) (string, error) `toml:"-"`
}

// TokenStorePath returns the path to the multi-account token store keyed off
// the config's parent directory. When Config.Path is unset (rare — only
// happens in tests that bypass Load), the helper falls back to the same
// resolution rules auth.NewStore uses so the two paths stay in sync.
func (c *Config) TokenStorePath() string {
	if c == nil {
		return ""
	}
	if c.Path != "" {
		return filepath.Join(filepath.Dir(c.Path), "tokens.json")
	}
	if xdg := os.Getenv("XDG_CONFIG_HOME"); xdg != "" {
		return filepath.Join(xdg, "superhuman-pp-cli", "tokens.json")
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return ""
	}
	return filepath.Join(home, ".config", "superhuman-pp-cli", "tokens.json")
}

func Load(configPath string) (*Config, error) {
	cfg := &Config{
		BaseURL: "https://mail.superhuman.com/~backend",
	}

	// Resolve config path
	path := configPath
	if path == "" {
		path = os.Getenv("SUPERHUMAN_CONFIG")
	}
	if path == "" {
		home, _ := os.UserHomeDir()
		path = filepath.Join(home, ".config", "superhuman-pp-cli", "config.toml")
	}
	cfg.Path = path

	// Try to load config file
	data, err := os.ReadFile(path)
	if err == nil {
		if err := toml.Unmarshal(data, cfg); err != nil {
			return nil, fmt.Errorf("parsing config %s: %w", path, err)
		}
	}

	// Env var overrides
	if v := os.Getenv("SUPERHUMAN_JWT"); v != "" {
		cfg.SuperhumanJwt = v
		cfg.AuthSource = "env:SUPERHUMAN_JWT"
	}

	// Label config-file-derived credentials so doctor can distinguish
	// "credentials persisted on disk" from "no credentials at all" — without
	// this, users who saved via set-token without an env var see a blank
	// auth_source and can't tell whether their config is being picked up.
	// The label is the literal "config" rather than "config:<path>"; the
	// config file path is exposed separately as report["config_path"], and
	// embedding it in auth_source leaks the user's home directory through
	// doctor's JSON envelope.
	if cfg.AuthSource == "" && (cfg.AuthHeaderVal != "" || cfg.AccessToken != "") {
		cfg.AuthSource = "config"
	}
	if cfg.AuthSource == "" && cfg.SuperhumanJwt != "" {
		cfg.AuthSource = "config"
	}

	// Base URL override (used by printing-press verify to point at mock/test servers)
	if v := os.Getenv("SUPERHUMAN_BASE_URL"); v != "" {
		cfg.BaseURL = v
	}
	return cfg, nil
}

// ResolveActiveEmail picks which token-store account the CLI should use for
// this invocation. Resolution:
//  1. If Config.ActiveEmail is set, return it iff it exists in the store;
//     otherwise return (ActiveEmail, ErrAccountNotFound) so the caller can
//     surface the user-supplied name in the error message.
//  2. Otherwise return the account with the largest LastUsedAt.
//  3. If no LastUsedAt values differ (all zero), return the lexicographically
//     first email so behaviour is deterministic.
//  4. If the store has no accounts (or fails to load), return ("", nil).
//
// Store load failures are treated as "no accounts" so callers can fall
// through to legacy auth paths (env var, config jwt) without needing to
// handle a transient I/O error themselves. The trade-off is debuggability —
// if the store is genuinely corrupt, the user sees a "no credentials" error
// rather than the underlying parse failure. That's acceptable because the
// legacy path is the documented fallback for exactly this case.
func (c *Config) ResolveActiveEmail() (string, error) {
	if c == nil {
		return "", nil
	}
	storePath := c.TokenStorePath()
	if storePath == "" {
		return "", nil
	}
	store := auth.NewStoreAt(storePath)
	p, err := store.Load()
	if err != nil || p == nil || len(p.Accounts) == 0 {
		// On load failure, behave as if the store doesn't exist. See
		// docstring rationale above.
		if c.ActiveEmail != "" {
			return c.ActiveEmail, ErrAccountNotFound
		}
		return "", nil
	}
	if c.ActiveEmail != "" {
		if _, ok := p.Accounts[c.ActiveEmail]; ok {
			return c.ActiveEmail, nil
		}
		return c.ActiveEmail, ErrAccountNotFound
	}
	// Pick the most-recently-used account. Tie-break on lexicographic order
	// so the choice is stable across invocations even when LastUsedAt is
	// unset on every account (common just after a multi-account login).
	var bestEmail string
	var bestLastUsed int64 = -1
	for email, acct := range p.Accounts {
		if acct.LastUsedAt > bestLastUsed ||
			(acct.LastUsedAt == bestLastUsed && (bestEmail == "" || email < bestEmail)) {
			bestEmail = email
			bestLastUsed = acct.LastUsedAt
		}
	}
	return bestEmail, nil
}

// AuthHeader returns the value to send in the Authorization header.
// Resolution precedence:
//  1. Explicit AuthHeaderVal (the literal-override path, e.g. `auth_header
//     = "..."` in config.toml or a Surf-mode preset).
//  2. Token store: the active account's SuperhumanToken.Token, if non-empty.
//  3. Legacy SuperhumanJwt (env var or config.toml `jwt = "..."`).
//  4. AccessToken (the older OAuth2-style path that some specs declare).
//  5. Empty string.
//
// As a side effect, AuthSource is updated to reflect which path resolved so
// `doctor` and `auth status` can show the user where the credential came
// from. AuthSource values introduced here:
//   - "token-store:<email>" when the store provided the token
// Existing values ("env:SUPERHUMAN_JWT", "config", "oauth2") are preserved
// for the legacy paths so any verification that asserts those strings keeps
// working.
//
// The header is derived on every call (not cached on the Client struct) so
// when a refresh rotates the token in the store, the next request picks up
// the new value automatically. The client cache key already hashes the
// AuthHeader output, so cache entries also invalidate when the token
// rotates — see Client.cacheKey for the hash incorporation.
func (c *Config) AuthHeader() string {
	if c == nil {
		return ""
	}
	if c.AuthHeaderVal != "" {
		return c.AuthHeaderVal
	}

	// Token-store path: take precedence over legacy SuperhumanJwt so a user
	// who has run `auth login --chrome` doesn't accidentally get pinned to
	// a stale paste-token if they happen to still have SUPERHUMAN_JWT in
	// their shell env. The legacy paths remain as fallbacks below.
	if email, err := c.ResolveActiveEmail(); err == nil && email != "" {
		store := auth.NewStoreAt(c.TokenStorePath())
		if acct, ok, getErr := store.Get(email); getErr == nil && ok && acct.SuperhumanToken.Token != "" {
			c.AuthSource = "token-store:" + email
			return "Bearer " + acct.SuperhumanToken.Token
		}
	}

	// Env-var token wins over file-stored AccessToken (env > config convention).
	if c.SuperhumanJwt != "" {
		// AuthSource may already be "env:SUPERHUMAN_JWT" from Load; if it's
		// some other value (e.g. "config" because we found jwt= in the
		// file), don't clobber it here. The original AuthHeader() always
		// set "env:SUPERHUMAN_JWT" unconditionally, which was a long-
		// standing bug — a config-file jwt would mis-report its source as
		// the env var.
		if c.AuthSource == "" {
			c.AuthSource = "config"
		}
		return applyAuthFormat("Bearer {token}", map[string]string{
			"jwt":            c.SuperhumanJwt,
			"SUPERHUMAN_JWT": c.SuperhumanJwt,
			"token":          c.SuperhumanJwt,
		})
	}
	if c.AccessToken != "" {
		c.AuthSource = "oauth2"
		return applyAuthFormat("Bearer {token}", map[string]string{"access_token": c.AccessToken, "token": c.AccessToken})
	}
	return ""
}

func applyAuthFormat(format string, replacements map[string]string) string {
	if format == "" {
		return ""
	}
	for key, value := range replacements {
		format = strings.ReplaceAll(format, "{"+key+"}", value)
	}
	if strings.Contains(format, "{") {
		return ""
	}
	return format
}

// SaveActiveEmail sets Config.ActiveEmail and persists the change to disk.
// Used by `auth use <email>` (R2c) to pin the active account across CLI
// invocations. Empty email clears the pin so the four-step resolver in
// ResolveActiveEmail falls back to most-recently-used.
//
// The on-disk write uses the same TOML marshaler as SaveTokens / ClearTokens
// so a hand-edited config.toml with comments will lose them on the next
// save — same trade-off the existing token-saving paths accept.
func (c *Config) SaveActiveEmail(email string) error {
	if c == nil {
		return fmt.Errorf("config: SaveActiveEmail on nil Config")
	}
	c.ActiveEmail = email
	return c.save()
}

func (c *Config) SaveTokens(clientID, clientSecret, accessToken, refreshToken string, expiry time.Time) error {
	c.ClientID = clientID
	c.ClientSecret = clientSecret
	c.AccessToken = accessToken
	c.RefreshToken = refreshToken
	c.TokenExpiry = expiry
	return c.save()
}

func (c *Config) ClearTokens() error {
	c.AccessToken = ""
	c.RefreshToken = ""
	c.TokenExpiry = time.Time{}
	return c.save()
}

func (c *Config) save() error {
	dir := filepath.Dir(c.Path)
	if err := os.MkdirAll(dir, 0o700); err != nil {
		return fmt.Errorf("creating config dir: %w", err)
	}
	data, err := toml.Marshal(c)
	if err != nil {
		return fmt.Errorf("marshaling config: %w", err)
	}
	return os.WriteFile(c.Path, data, 0o600)
}

